<?php namespace App\Services\Finance; use App\Models\{BillingDocument,PaymentRecord}; use Illuminate\Support\Str;
class PaymentNumberGenerator{public function payment():string{return $this->unique('PAY',PaymentRecord::class,'payment_number');}public function document(string $type):string{return $this->unique(match($type){'receipt'=>'RCP','credit_note'=>'CRN',default=>'INV'},BillingDocument::class,'document_number');}private function unique(string $prefix,string $model,string $column):string{do{$number=$prefix.'-'.now()->format('Ymd').'-'.strtoupper(Str::random(4));}while($model::where($column,$number)->exists());return $number;}}
